{
  "candidate_pair": {
    "canonical_pair_id": "conn_dev_pair_222c986cd9853739",
    "ko_a": {
      "canonical_ko_id": "conn_dev_ko_006",
      "canonical_name": "Gradient Descent",
      "canonical_type": "Method",
      "aliases": [],
      "groundings": [
        {
          "lecture_id": "unconstrained_optimisation_001",
          "source_spans": [
            "Gradient descent requires the gradient of the objective function."
          ]
        },
        {
          "lecture_id": "least_squares_learning_001",
          "source_spans": [
            "Gradient descent can be applied to ordinary least squares by using the gradient of this objective function."
          ]
        }
      ]
    },
    "ko_b": {
      "canonical_ko_id": "conn_dev_ko_017",
      "canonical_name": "Least Squares Objective",
      "canonical_type": "Concept",
      "aliases": [],
      "groundings": [
        {
          "lecture_id": "maximum_likelihood_001",
          "source_spans": [
            "maximizing the log-likelihood is equivalent to minimizing the least squares objective"
          ]
        },
        {
          "lecture_id": "least_squares_learning_001",
          "source_spans": [
            "Ordinary least squares fits a linear regression model by minimizing the least squares objective"
          ]
        }
      ]
    }
  },
  "evidence_catalog": [
    {
      "evidence_id": "evidence_001",
      "lecture_id": "unconstrained_optimisation_001",
      "span": "An objective function assigns a scalar value to each candidate parameter vector. Unconstrained optimisation seeks a parameter vector that minimizes this objective function."
    },
    {
      "evidence_id": "evidence_002",
      "lecture_id": "unconstrained_optimisation_001",
      "span": "Gradient descent requires the gradient of the objective function. With step size \\(\\alpha_k>0\\), the method moves opposite to the gradient. The gradient descent update is"
    },
    {
      "evidence_id": "evidence_003",
      "lecture_id": "unconstrained_optimisation_001",
      "span": "\\[\nx_{k+1}=x_k-\\alpha_k\\nabla f(x_k).\n\\]"
    },
    {
      "evidence_id": "evidence_004",
      "lecture_id": "unconstrained_optimisation_001",
      "span": "For a small proposed displacement, the first-order Taylor approximation predicts the resulting objective change. This explains why a displacement opposite to the gradient is locally descending when the step size is sufficiently small."
    },
    {
      "evidence_id": "evidence_005",
      "lecture_id": "unconstrained_optimisation_001",
      "span": "The Newton optimisation method additionally requires the Hessian matrix to model local curvature. When the Hessian is invertible, the Newton optimisation update is"
    },
    {
      "evidence_id": "evidence_006",
      "lecture_id": "unconstrained_optimisation_001",
      "span": "\\[\nx_{k+1}=x_k-H_f(x_k)^{-1}\\nabla f(x_k).\n\\]"
    },
    {
      "evidence_id": "evidence_007",
      "lecture_id": "unconstrained_optimisation_001",
      "span": "The Newton optimisation method can take a full curvature-adjusted step, whereas gradient descent controls movement through an explicit step size."
    },
    {
      "evidence_id": "evidence_008",
      "lecture_id": "maximum_likelihood_001",
      "span": "A statistical model is a family of probability distributions indexed by an unknown parameter \\(\\theta\\). For observed data, the log-likelihood measures how the assumed parameter value supports those observations."
    },
    {
      "evidence_id": "evidence_009",
      "lecture_id": "maximum_likelihood_001",
      "span": "Maximum likelihood estimation treats the log-likelihood as an objective function and selects a parameter value that maximizes it. The score function is the gradient of the log-likelihood with respect to the parameter,"
    },
    {
      "evidence_id": "evidence_010",
      "lecture_id": "maximum_likelihood_001",
      "span": "\\[\ns(\\theta)=\\nabla_{\\theta}\\ell(\\theta).\n\\]"
    },
    {
      "evidence_id": "evidence_011",
      "lecture_id": "maximum_likelihood_001",
      "span": "At an interior differentiable maximum, a candidate satisfies the score equation \\(s(\\theta)=0\\). Finding such a candidate is a root-finding problem. When the score equation has no closed-form solution, Newton's root-finding method can be applied within maximum likelihood estimation."
    },
    {
      "evidence_id": "evidence_012",
      "lecture_id": "maximum_likelihood_001",
      "span": "For a Gaussian linear regression model with constant variance, maximizing the log-likelihood is equivalent to minimizing the least squares objective. Under this assumption, ordinary least squares and maximum likelihood estimation select the same coefficient vector."
    },
    {
      "evidence_id": "evidence_013",
      "lecture_id": "least_squares_learning_001",
      "span": "Linear regression models a response using a linear function of the input features. Ordinary least squares fits a linear regression model by minimizing the least squares objective over the coefficient vector \\(\\beta\\)."
    },
    {
      "evidence_id": "evidence_014",
      "lecture_id": "least_squares_learning_001",
      "span": "For observations \\((x_i,y_i)\\), the mean squared error formula is"
    },
    {
      "evidence_id": "evidence_015",
      "lecture_id": "least_squares_learning_001",
      "span": "\\[\n\\operatorname{MSE}(\\beta)=\\frac{1}{n}\\sum_{i=1}^{n}(y_i-x_i^\\top\\beta)^2.\n\\]"
    },
    {
      "evidence_id": "evidence_016",
      "lecture_id": "least_squares_learning_001",
      "span": "This formula formalizes the least squares objective up to a positive constant scaling. Gradient descent can be applied to ordinary least squares by using the gradient of this objective function."
    },
    {
      "evidence_id": "evidence_017",
      "lecture_id": "least_squares_learning_001",
      "span": "Ridge regression extends ordinary least squares by adding a squared-coefficient penalty to the objective. The penalty can improve numerical stability and reduce sensitivity to highly correlated features."
    },
    {
      "evidence_id": "evidence_018",
      "lecture_id": "least_squares_learning_001",
      "span": "Under a Gaussian noise model, ordinary least squares also has a maximum likelihood estimation interpretation. That equivalence depends on the statistical assumptions and is not an identity between the two methods in every model."
    }
  ]
}
